parameters.body:
={
  "model": "llama-3.1-8b-instant",
  "messages": [
    {
      "role": "system",
      "content": "You are an elite dropshipping advisor for EliteStore Pakistan. The user will provide a list of available products with their wholesale and retail prices. You must select the top 3 best products for a reseller to promote. Choose ones with good profit margins or general mass appeal.\n\nYou MUST reply with ONLY a valid JSON object in this exact format:\n{\n  \"recommendations\": [\n    {\n      \"product_name\": \"Name of product\",\n      \"reason\": \"A short, catchy 1-sentence reason why they should sell this (e.g. 'High profit margin of Rs. 500, perfect for summer!'). Mix of English and Roman Urdu.\"\n    }\n  ]\n}"
    },
    {
      "role": "user",
      "content": {{ JSON.stringify($json.body.products_data) }}
    }
  ],
  "temperature": 0.6,
  "max_tokens": 400,
  "response_format": {"type": "json_object"}
}

parameters.jsCode:
try {
  const rawReply = $input.first().json.choices[0].message.content.trim();
  const parsed = JSON.parse(rawReply);
  return [{ json: { success: true, data: parsed } }];
} catch (e) {
  return [{ json: { success: false, error: e.message } }];
}
